@startuml
title **SectionType Referenced-by View**

skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor<<work-product-component>> #FFB800
  BorderColor<<work-product-component>> #FFB800
  BackgroundColor<<reference-data>> #00BFA5
  BorderColor<<reference-data>> #00BFA5
  BackgroundColor<<Abstraction>> #64B5F6
  BorderColor<<Abstraction>> #64B5F6
}

package "work-product-component Entities" {
  class "TubularComponent" <<work-product-component>> {
    SectionTypeID
  }
}

class "AbstractReferenceType" <<Abstraction>> {
}

class "SectionType" <<reference-data>> {
}

"TubularComponent" --> "SectionType" : " "
"SectionType" --|> "AbstractReferenceType"

@enduml
